import{c as r,a7 as t,y as a,B as o}from"./chunks/framework.3cjvm90C.js";const d=JSON.parse('{"title":"自学计算机科学","description":"计算机科学自学资源与学习方法指南","frontmatter":{"title":"自学计算机科学","description":"计算机科学自学资源与学习方法指南"},"headers":[],"relativePath":"toolbox/study/cs_techself.md","filePath":"toolbox/study/cs_techself.md","lastUpdated":1782448598000}'),n={name:"toolbox/study/cs_techself.md"};function s(l,e,p,h,c,b){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="自学计算机科学" tabindex="-1">自学计算机科学 <a class="header-anchor" href="#自学计算机科学" aria-label="Permalink to “自学计算机科学”">​</a></h1><blockquote><p>本文档是对 <a href="https://teachyourselfcs.com" target="_blank" rel="noreferrer">TeachYourselfCS</a> 内容的中文翻译，原作者为 <a href="https://twitter.com/oznova_" target="_blank" rel="noreferrer">Ozan Onay</a> 和 <a href="https://twitter.com/quackingduck" target="_blank" rel="noreferrer">Myles Byrne</a>。如需了解翻译相关信息或帮助改进翻译，请参见 <a href="#这份指引是谁翻译的">本文档结尾</a>。</p><p>This document is a Chinese translation of <a href="https://teachyourselfcs.com" target="_blank" rel="noreferrer">TeachYourselfCS</a>, which is written by <a href="https://twitter.com/oznova_" target="_blank" rel="noreferrer">Ozan Onay</a> and <a href="https://twitter.com/quackingduck" target="_blank" rel="noreferrer">Myles Byrne</a>. For more information about this translation, please refer to <a href="#这份指引是谁翻译的">the end of this document</a>.</p></blockquote><p>如果你是一个自学成才的工程师，或者从编程培训班毕业，那么你很有必要学习计算机科学。幸运的是，不必为此花上数年光阴和不菲费用去攻读一个学位：仅仅依靠自己，你就可以获得世界一流水平的教育💸。</p><p>互联网上，到处都有许多的学习资源，然而精华与糟粕并存。你所需要的，不是一个诸如「200+ 免费在线课程」的清单，而是以下问题的答案：</p><ul><li>你应当学习 <strong>哪些科目</strong>，为什么？</li><li>对于这些科目，<strong>最好的书籍或者视频课程</strong> 是什么？</li></ul><p>在这份指引中，我们尝试对这些问题做出确定的回答。</p><h2 id="简而言之" tabindex="-1">简而言之 <a class="header-anchor" href="#简而言之" aria-label="Permalink to “简而言之”">​</a></h2><p>大致按照列出的顺序，借助我们所建议的教材或者视频课程（但是最好二者兼用），学习如下的九门科目。目标是先花 100 到 200 个小时学习完每一个科目，然后在你职业生涯中，不时温习其中的精髓🚀。</p><table tabindex="0"><thead><tr><th>科目</th><th>为何要学？</th><th>最佳书籍</th><th>最佳视频</th></tr></thead><tbody><tr><td><a href="#编程">编程</a></td><td>不要做一个「永远没彻底搞懂」诸如递归等概念的程序员。</td><td><a href="https://book.douban.com/subject/1148282/" target="_blank" rel="noreferrer">《计算机程序的构造和解释》</a></td><td>Brian Harvey ’s Berkeley CS 61A</td></tr><tr><td><a href="#计算机系统结构">计算机系统结构</a></td><td>如果你对于计算机如何工作没有具体的概念，那么你所做出的所有高级抽象都是空中楼阁。</td><td><a href="https://book.douban.com/subject/26912767/" target="_blank" rel="noreferrer">《深入理解计算机系统》</a></td><td>Berkeley CS 61C</td></tr><tr><td><a href="#算法和数据结构">算法与数据结构</a></td><td>如果你不懂得如何使用栈、队列、树、图等常见数据结构，遇到有难度的问题时，你将束手无策。</td><td><a href="https://book.douban.com/subject/4048566/" target="_blank" rel="noreferrer">《算法设计手册》</a></td><td>Steven Skiena ’s lectures</td></tr><tr><td><a href="#数学知识">数学知识</a></td><td>计算机科学基本上是应用数学的一个「跑偏的」分支，因此学习数学将会给你带来竞争优势。</td><td><a href="https://book.douban.com/subject/33396340/" target="_blank" rel="noreferrer">《计算机科学中的数学》</a></td><td>Tom Leighton ’s MIT 6.042J</td></tr><tr><td><a href="#操作系统">操作系统</a></td><td>你所写的代码，基本上都由操作系统来运行，因此你应当了解其运作的原理。</td><td><a href="https://book.douban.com/subject/33463930/" target="_blank" rel="noreferrer">《操作系统导论》</a></td><td>Berkeley CS 162</td></tr><tr><td><a href="#计算机网络">计算机网络</a></td><td>互联网已然势不可挡：理解工作原理才能解锁全部潜力。</td><td><a href="https://book.douban.com/subject/30280001/" target="_blank" rel="noreferrer">《计算机网络：自顶向下方法》</a></td><td>Stanford CS 144</td></tr><tr><td><a href="#数据库">数据库</a></td><td>对于多数重要程序，数据是其核心，然而很少人理解数据库系统的工作原理。</td><td><em><a href="https://book.douban.com/subject/2256069/" target="_blank" rel="noreferrer">Readings in Database Systems</a></em> （暂无中译本）</td><td>Joe Hellerstein ’s Berkeley CS 186</td></tr><tr><td><a href="#编程语言与编译器">编程语言与编译器</a></td><td>若你懂得编程语言和编译器如何工作，你就能写出更好的代码，更轻松地学习新的编程语言。</td><td><em><a href="https://craftinginterpreters.com/" target="_blank" rel="noreferrer">Crafting Interpreters</a></em></td><td>Alex Aiken ’s course on Lagunita</td></tr><tr><td><a href="#分布式系统">分布式系统</a></td><td>如今，<strong>多数</strong> 系统都是分布式的。</td><td><a href="https://book.douban.com/subject/30329536/" target="_blank" rel="noreferrer">《数据密集型应用系统设计》</a></td><td>MIT 6.824</td></tr></tbody></table><h2 id="还是太多" tabindex="-1">还是太多？ <a class="header-anchor" href="#还是太多" aria-label="Permalink to “还是太多？”">​</a></h2><p>如果花几年时间自学 9 门科目让人望而却步，我们建议你只专注于两本书：<strong>《深入理解计算机系统》</strong> 和 <strong>《数据密集型应用系统设计》</strong>。根据我们的经验，投入到这两本书的时间可以获得极高的回报率，特别适合从事网络应用开发的自学工程师。这两本书也可以作为上面表格中其他科目的纲领。</p><h2 id="为什么要学习计算机科学" tabindex="-1">为什么要学习计算机科学？ <a class="header-anchor" href="#为什么要学习计算机科学" aria-label="Permalink to “为什么要学习计算机科学？”">​</a></h2><p>软件工程师分为两种：一种充分理解了计算机科学，从而有能力应对充满挑战的创造性工作；另一种仅仅凭着对一些高级工具的熟悉而勉强应付。</p><p>这两种人都自称软件工程师，都能在职业生涯早期挣到差不多的工资。然而，随着时间流逝，第一种工程师不断成长，所做的事情将会越来越有意义且更为高薪，不论是有价值的商业工作、突破性的开源项目、技术上的领导力或者高质量的个人贡献。</p><blockquote><p>全球短信系统每日收发约 200 亿条信息，而仅仅靠 57 名工程师，现在的 WhatsApp 每日收发 420 亿条。</p><p>— Benedict Evans (@BenedictEvans) <a href="https://twitter.com/BenedictEvans/status/694342874729545729" target="_blank" rel="noreferrer">2016 年 2 月 2 日</a></p></blockquote><p>第一种工程师总是寻求深入学习计算机科学的方法，或是通过传统的方法学习，或是在职业生涯中永无止息地学习；第二种工程师通常浮于表面，只学习某些特定的工具和技术，而不研究其底层的基本原理，仅仅在技术潮流的风向改变时学习新的技能。</p><p>如今，涌入计算机行业的人数激增，然而计算机专业的毕业生数量基本上未曾改变。第二种工程师的供过于求正在开始减少他们的工作机会，使他们无法涉足行业内更加有意义的工作。对你而言，不论正在努力成为第一种工程师，还是只想让自己的职业生涯更加安全，学习计算机科学是唯一可靠的途径。</p><h2 id="分科目指引" tabindex="-1">分科目指引 <a class="header-anchor" href="#分科目指引" aria-label="Permalink to “分科目指引”">​</a></h2><h3 id="编程" tabindex="-1">编程 <a class="header-anchor" href="#编程" aria-label="Permalink to “编程”">​</a></h3><p>大多数计算机专业本科教学以程序设计「导论」作为开始。这类课程的最佳版本不仅能满足初学者的需要，还适用于那些在初学编程阶段遗漏了某些有益的概念和程序设计模式的人。</p><p>对于这部分内容，我们的标准推荐是这部经典著作：<a href="https://book.douban.com/subject/1148282/" target="_blank" rel="noreferrer">《计算机程序的构造和解释》</a>。在网络上，这本书既可供 <a href="https://mitpress.mit.edu/sites/default/files/sicp/full-text/book/book.html" target="_blank" rel="noreferrer">免费阅读（英文版）</a>，也作为 <a href="http://ocw.mit.edu/courses/electrical-engineering-and-computer-science/6-001-structure-and-interpretation-of-computer-programs-spring-2005/video-lectures/" target="_blank" rel="noreferrer">MIT 的免费视频课程</a>。不过尽管这些视频课程很不错，我们对于视频课程的推荐实际上是 <a href="https://archive.org/details/ucberkeley-webcast-PL3E89002AA9B9879E?sort=titleSorter" target="_blank" rel="noreferrer">Brian Harvey 开设的 SICP 课程</a>（即 Berkeley 的 61A 课程）。比起 MIT 的课程，它更加完善，更适用于初学者。</p><p>我们建议至少学完 SICP 的前三章，并完成配套的习题。如果需要额外的练习，可以去解决一些小的程序设计问题，比如 <a href="http://exercism.io" target="_blank" rel="noreferrer">exercism</a>。</p><blockquote><p><strong>中文翻译新增：</strong></p><ul><li>关于 SICP 国内视频观看地址 <ul><li><a href="https://www.bilibili.com/video/av8515129/" target="_blank" rel="noreferrer">MIT 的免费视频课程（中英字幕）</a></li><li><a href="https://www.bilibili.com/video/av40460492/" target="_blank" rel="noreferrer">Brian Harvey 开设的 SICP 课程（英文字幕）</a></li></ul></li><li>Scheme 学习的相关资源参见：<a href="https://github.com/DeathKing/Learning-SICP" target="_blank" rel="noreferrer">https://github.com/DeathKing/Learning-SICP</a></li><li>更详细的补充说明：<a href="https://github.com/izackwu/TeachYourselfCS-CN/issues/3" target="_blank" rel="noreferrer">#3</a></li></ul></blockquote><p>自从 2016 年首次发布这份指南以来，最常被问到的一个问题是，我们是否推荐由 John DeNero 讲授的更新的 CS 61A 课程，以及配套的书籍 <a href="https://composingprograms.com/" target="_blank" rel="noreferrer"><em>Composing Programs</em></a>，这本书「继承自 SICP」 但使用 Python 讲解。我们认为 DeNero 的课程也很不错，有的学生可能更喜欢，但我们还是建议把 SICP、Scheme 和 Brian Harvey 的视频课程作为首选。</p><p>为什么这么说呢？因为 SICP 是独一无二的，它可以——至少很有可能——改变你对计算机和编程的基本认识。不是每个人都有这样的体验。有的人讨厌这本书，有的人看了前几页就放弃了。但潜在的回报让它值得一读。</p><p>如果你觉得 SICP 过于难，试试 <em>Composing Programs</em>。如果还是不合适，那我们推荐 《程序设计方法》（<a href="https://book.douban.com/subject/1140942/" target="_blank" rel="noreferrer">中文版</a>，<a href="http://www.htdp.org/" target="_blank" rel="noreferrer">英文版</a>） ；如果你觉得 SICP 过于简单，那我们推荐 <a href="https://book.douban.com/subject/1782316/" target="_blank" rel="noreferrer"><em>Concepts, Techniques, and Models of Computer Programming</em></a>。如果读这些书让你觉得没有收获，也许你应该先学习其他科目，一两年后再重新审视编程的理念。</p><blockquote><p>新版原文删除了对 <em>Concepts, Techniques, and Models of Computer Programming</em> 一书的推荐，但这本书对各种编程模型有深入的见解，值得一读。所以译文中依然保留。 — 译者注</p></blockquote><p>最后，有一点要说明的是：本指南 <strong>不适用</strong> 于完全不懂编程的新手。我们假定你是一个没有计算机专业背景的程序员，希望填补一些知识空白。事实上，我们把「编程」章节包括进来只是提醒你还有更多知识需要学习。对于那些从来没有学过编程，但又想学的人来说，这份 <a href="https://www.reddit.com/r/learnprogramming/wiki/faq#wiki_getting_started" target="_blank" rel="noreferrer">指南</a> 更合适。</p><p><a href="https://book.douban.com/subject/1148282/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66758473-ef7bff80-eed0-11e9-944a-15ae5c8542ca.jpg" alt="计算机程序的构造和解释"></a></p><h3 id="计算机系统结构" tabindex="-1">计算机系统结构 <a class="header-anchor" href="#计算机系统结构" aria-label="Permalink to “计算机系统结构”">​</a></h3><p>计算机系统结构——有时候又被称为「计算机系统」或者「计算机组成」——是了解软件底层的的重要视角。根据我们的经验，这是自学的软件工程师最容易忽视的领域。</p><p>我们最喜欢的入门书是 <a href="https://book.douban.com/subject/26912767/" target="_blank" rel="noreferrer">《深入理解计算机系统》</a>。典型的 <a href="http://csapp.cs.cmu.edu/3e/courses.html" target="_blank" rel="noreferrer">计算机体系结构导论课程</a> 会涵盖本书的 1-6 章。</p><p>我们喜爱《深入理解计算机系统》，因为它的实用性，并且站在程序员的视角。虽然计算机体系结构的内容比本书所涉及的内容多得多，但对于那些想了解计算机系统以求编写更快、更高效、更可靠的软件的人来说，这本书是很好的起点。</p><p>对于那些既想了解这个主题又想兼顾硬件和软件的知识的人来说，我们推荐 <a href="https://book.douban.com/subject/1998341/" target="_blank" rel="noreferrer">《计算机系统要素》</a>，又名「从与非门到俄罗斯方块」（Nand2Tetris），这本书规模宏大，让读者对计算机内的所有部分如何协同工作有完全的认识。这本书的每一章节对应如何构建计算机整体系统中的一小部分，从用 HDL （硬件描述语言）写基本的逻辑门电路出发，途经 CPU 和汇编，最终抵达诸如俄罗斯方块这般规模的应用程序。</p><p>我们推荐把此书的前六章读完，并完成对应的项目练习。这么做，你将更加深入地理解，计算机体系结构和运行其上的软件之间的关系。</p><p>这本书的前半部分（包括所有对应的项目）均可从 <a href="http://www.nand2tetris.org" target="_blank" rel="noreferrer">Nand2Tetris 的网站上</a> 免费获得。同时，在 Coursera 上，这是一门 <a href="https://www.coursera.org/learn/build-a-computer" target="_blank" rel="noreferrer">视频课程</a>。</p><p>为了追求简洁和紧凑，这本书牺牲了内容上的深度。尤其值得注意的是，流水线和存储层次结构是现代计算机体系结构中极其重要的两个概念，然而这本书对此几乎毫无涉及。</p><p>当你掌握了 Nand2Tetris 的内容后，我们推荐要么回到《深入理解计算机系统》，或者考虑 Patterson 和 Hennessy 二人所著的 <a href="https://book.douban.com/subject/26604008/" target="_blank" rel="noreferrer">《计算机组成与设计》</a>，一本优秀的经典著作。这本书中的不同章节重要程度不一，因此我们建议根据 Berkeley 的 <a href="http://inst.eecs.berkeley.edu/~cs61c/sp15/" target="_blank" rel="noreferrer">CS61C 课程</a> 「计算机体系结构中的伟大思想」来着重阅读一些章节。这门课的笔记和实验在网络上可以免费获得，并且在 <a href="https://archive.org/details/ucberkeley-webcast-PL-XXv-cvA_iCl2-D-FS5mk0jFF6cYSJs_" target="_blank" rel="noreferrer">互联网档案</a> 中有这门课程的过往资料。</p><p><a href="https://book.douban.com/subject/26912767/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20510068/82109944-12270d00-976d-11ea-85a9-774e4f762ec9.png" alt="深入理解计算机系统"></a> <a href="http://www.nand2tetris.org" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66758695-60231c00-eed1-11e9-8422-a4acfb10a390.jpg" alt="计算机系统要素"></a></p><blockquote><p>硬件是平台。</p><p>— Mike Acton, Engine Director at Insomniac Games （<a href="https://www.youtube.com/watch?v=rX0ItVEVjHc" target="_blank" rel="noreferrer">观看他在 CppCon 上的演说</a>）</p></blockquote><h3 id="算法与数据结构" tabindex="-1">算法与数据结构 <a class="header-anchor" href="#算法与数据结构" aria-label="Permalink to “算法与数据结构”">​</a></h3><p>正如几十年来的共识，我们认为，计算机科学教育所赋予人们的最大能量在于对常见算法和数据结构的熟悉。此外，这也可以训练一个人对于各种问题的解决能力，有助于其他领域的学习。</p><p>关于算法与数据结构，有成百上千的书可供使用，但是我们的最爱是 Steven Skiena 编写的 <a href="https://book.douban.com/subject/4048566/" target="_blank" rel="noreferrer">《算法设计手册》</a> 。显而易见，他对此充满热爱，迫不及待地想要帮助其他人理解。在我们看来，这本书给人一种焕然一新的体验，完全不同于那些更加经常被推荐的书（比如 Cormen、Leiserson、Rivest、Stein 或 Sedgewick 的书，后两者充斥着过多的证明，不适合以 <strong>解决问题</strong> 为导向的学习）。</p><p>如果你更喜欢视频课程，<a href="https://www.youtube.com/watch?v=A2bFN3MyNDA&amp;list=PLOtl7M3yp-DX32N0fVIyvn7ipWKNGmwpp" target="_blank" rel="noreferrer">Skiena 慷慨地提供了他的课程</a>。此外， Tim Roughgarden 的课程也很不错，在 Stanford 的 MOOC 平台 Lagunita，或者 <a href="https://www.coursera.org/specializations/algorithms" target="_blank" rel="noreferrer">Coursera</a> 上均可获得。Skiena 和 Roughgarden 的这两门课程没有优劣之分，选择何者取决于个人品味。</p><p>至于练习，我们推荐学生在 <a href="https://leetcode.com" target="_blank" rel="noreferrer">Leetcode</a> 上解决问题。Leetcode 上的问题往往有趣且带有良好的解法和讨论。此外，在竞争日益激烈的软件行业，这些问题可以帮助你评估自己应对技术面试中常见问题的能力。我们建议解决大约 100 道随机挑选的 Leetcode 问题，作为学习的一部分。</p><p>最后，我们强烈推荐 <a href="https://book.douban.com/subject/2124114/" target="_blank" rel="noreferrer">《怎样解题》</a>。这本书极为优秀且独特，指导人们解决广义上的问题，因而一如其适用于数学，它适用于计算机科学。</p><p><a href="https://book.douban.com/subject/4048566/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66759121-361e2980-eed2-11e9-913c-8fc48c67122a.jpg" alt="算法设计手册"></a> <a href="https://book.douban.com/subject/2124114/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66759282-8e552b80-eed2-11e9-89de-16b1f8d82e78.jpg" alt="怎样解题"></a></p><blockquote><p>我可以广泛推荐的方法只有一个： 写之前先思考。</p><p>— Richard Hamming</p></blockquote><h3 id="数学知识" tabindex="-1">数学知识 <a class="header-anchor" href="#数学知识" aria-label="Permalink to “数学知识”">​</a></h3><p>从某个角度说，计算机科学是应用数学的一个「发育过度」的分支。尽管许多软件工程师试图——并且在不同程度上成功做到——忽视这一点，我们鼓励你用学习来拥抱数学。如若成功，比起那些没有掌握数学的人，你将获得巨大的竞争优势。</p><p>对于计算机科学，数学中最相关的领域是「离散数学」，其中的「离散」与「连续」相对立，大致上指的是应用数学中那些有趣的主题，而不是微积分之类的。由于定义比较含糊，试图掌握离散数学的全部内容是没有意义的。较为现实的学习目标是，了解逻辑、排列组合、概率论、集合论、图论以及密码学相关的一些数论知识。考虑到线性代数在计算机图形学和机器学习中的重要性，该领域同样值得学习。</p><p>学习离散数学，我们建议从 <a href="http://www.cs.elte.hu/~lovasz/dmbook.ps" target="_blank" rel="noreferrer">L ászl ó Lov ász 的课程笔记</a> 开始。Lov ász 教授成功地让这些内容浅显易懂且符合直觉，因此，比起正式的教材，这更适合初学者。</p><p>对于更加高阶的学习，我们推荐 <a href="https://book.douban.com/subject/33396340/" target="_blank" rel="noreferrer">《计算机科学中的数学》</a>， MIT 同名课程的课程笔记，篇幅与书籍相当（事实上，现已出版）。这门课程的视频同样 <a href="https://ocw.mit.edu/courses/electrical-engineering-and-computer-science/6-042j-mathematics-for-computer-science-fall-2010/video-lectures/" target="_blank" rel="noreferrer">可免费获得</a>，是我们所推荐的学习视频。</p><p>对于线性代数，我们建议从 <a href="https://www.youtube.com/playlist?list=PLZHQObOWTQDPD3MizzM2xVFitgF8hE_ab" target="_blank" rel="noreferrer">Essence of linear algebra</a> 系列视频开始，然后再去学习 Gilbert Strang 的 <a href="https://book.douban.com/subject/34820335/" target="_blank" rel="noreferrer">《线性代数导论》</a> 和 <a href="https://ocw.mit.edu/courses/mathematics/18-06-linear-algebra-spring-2010/video-lectures/" target="_blank" rel="noreferrer">视频课程</a>。</p><p><a href="https://book.douban.com/subject/33396340/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66759673-4387e380-eed3-11e9-8469-3e677d108e91.jpg" alt="计算机科学中的数学"></a></p><blockquote><p>如果人们不相信数学是简单的，那么只能是因为他们没有意识到生活有多么复杂。</p><p>— John von Neumann</p></blockquote><h3 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to “操作系统”">​</a></h3><p><a href="https://book.douban.com/subject/30297919/" target="_blank" rel="noreferrer">《操作系统概念》</a>（「恐龙书」）和 <a href="https://book.douban.com/subject/27096665/" target="_blank" rel="noreferrer">《现代操作系统》</a> 是操作系统领域的经典书籍。二者都因为写作风格和对学生不友好而招致了一些批评。</p><p><a href="https://book.douban.com/subject/33463930/" target="_blank" rel="noreferrer">《操作系统导论》（<em>Operating Systems: Three Easy Pieces</em>）</a> 是一个不错的替代品，并且 <a href="http://pages.cs.wisc.edu/~remzi/OSTEP/" target="_blank" rel="noreferrer">可在网上免费获得（英文版）</a>。我们格外喜欢这本书的结构，并且认为这本书的习题很值得一做。</p><p>在读完《操作系统导论》后，我们鼓励你探索特定操作系统的设计。可以借助「{OS name} Internals」风格的书籍，比如 <a href="https://www.amazon.com/Lions-Commentary-Unix-John/dp/1573980137/" target="_blank" rel="noreferrer"><em>Lion&#39;s commentary on Unix</em></a>， <a href="https://www.amazon.com/Design-Implementation-FreeBSD-Operating-System/dp/0321968972/" target="_blank" rel="noreferrer"><em>The Design and Implementation of the FreeBSD Operating System</em></a>，以及 <a href="https://www.amazon.com/Mac-OS-Internals-Systems-Approach/dp/0321278542/" target="_blank" rel="noreferrer"><em>Mac OS X Internals</em></a>。对于 Linux，我们推荐 Robert Love 的 <a href="https://book.douban.com/subject/6097773/" target="_blank" rel="noreferrer">《Linux 内核设计与实现》</a>。</p><p>为了巩固对操作系统的理解，阅读小型系统内核的代码并且为其增加特性是一个很不错的方法。比如，<a href="https://pdos.csail.mit.edu/6.828/2016/xv6.html" target="_blank" rel="noreferrer">xv6</a>，由 MIT 的一门课程所维护的从 Unix V6 到 ANSI C 和 x86 的移植，就是一个很棒的选择。《操作系统导论》有一个附录，记载了一些可能的 <a href="http://pages.cs.wisc.edu/~remzi/OSTEP/lab-projects-xv6.pdf" target="_blank" rel="noreferrer">xv6 实验项目</a>，其中充满了关于潜在项目的很棒想法。</p><p><a href="https://book.douban.com/subject/33463930/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66759780-78943600-eed3-11e9-8eb5-6472c318c265.jpg" alt="操作系统导论"></a></p><h3 id="计算机网络" tabindex="-1">计算机网络 <a class="header-anchor" href="#计算机网络" aria-label="Permalink to “计算机网络”">​</a></h3><p>鉴于有那么多关于网络服务端和客户端的软件工程，计算机网络是计算机科学中价值最为「立竿见影」的领域之一。我们的学生，系统性地学习了计算机网络，最终能够理解那些曾困扰他们多年的术语、概念和协议。</p><p>在这一主题上，我们最爱的书籍是 <a href="https://book.douban.com/subject/30280001/" target="_blank" rel="noreferrer">《计算机网络：自顶向下方法》</a>。书中的小项目和习题相当值得练习，尤其是其中的「Wireshark labs」（<a href="http://www-net.cs.umass.edu/wireshark-labs/" target="_blank" rel="noreferrer">这部分在网上可以获得</a>）。</p><p>如果更喜欢视频课程，我们推荐 Stanford 的 <a href="https://lagunita.stanford.edu/courses/Engineering/Networking-SP/SelfPaced/about" target="_blank" rel="noreferrer"><em>Introduction to Computer Networking</em></a>，可在他们的 MOOC 平台 Lagunita 上免费观看。</p><p>对于计算机网络的学习，做项目比完成小的习题更有益。一些可能的项目有： HTTP 服务器，基于 UDP 的聊天 APP，<a href="http://jvns.ca/blog/2014/08/12/what-happens-if-you-write-a-tcp-stack-in-python/" target="_blank" rel="noreferrer">迷你 TCP 栈</a>，代理，负载均衡器，或者分布式哈希表。</p><p><a href="https://book.douban.com/subject/30280001/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66760004-d9bc0980-eed3-11e9-9b3f-74bf54b9571f.jpg" alt="《计算机网络：自顶向下方法》"></a></p><blockquote><p>你无法盯着水晶球预见未来，未来的互联网何去何从取决于社会。</p><p>— Bob Kahn</p></blockquote><h3 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to “数据库”">​</a></h3><p>比起其他主题，自学数据库系统需要更多的付出。这是一个相对年轻的研究领域，并且出于很强的商业动机，研究者把想法藏在紧闭的门后。此外，许多原本有潜力写出优秀教材的作者反而选择了加入或创立公司。</p><p>鉴于如上情况，我们鼓励自学者大体上抛弃教材，而是从 <a href="https://archive.org/details/UCBerkeley_Course_Computer_Science_186" target="_blank" rel="noreferrer">2015 年春季学期的 CS 186 课程</a>（Joe Hellerstein 在 Berkeley 的数据库课程）开始，然后前往阅读论文。</p><p>对于初学者，有一篇格外值得提及的论文：<a href="http://db.cs.berkeley.edu/papers/fntdb07-architecture.pdf" target="_blank" rel="noreferrer"><em>Architecture of a Database System</em></a>。这篇论文提供了独特的对关系型数据库管理系统（RDBMS）如何工作的高层次观点，是后续学习的实用梗概。</p><p><a href="https://book.douban.com/subject/2256069/" target="_blank" rel="noreferrer"><em>Readings in Database Systems</em></a>，或者以 <a href="http://www.redbook.io/" target="_blank" rel="noreferrer">数据库「红书」</a> 更为人知，是由 Peter Bailis、Joe Hellerstein 和 Michael Stonebraker 编纂的论文合集。对于那些想要在 CS 186 课程的水平更进一步的学习者，「红书」应当是下一步。</p><p>如果你坚持一定要一本导论教材，那我们推荐 Ramakrishnan 和 Gehrke 所著的 <a href="https://book.douban.com/subject/1155934/" target="_blank" rel="noreferrer">《数据库管理系统：原理与设计》</a>。如需更深一步， Jim Gray 的经典著作 <a href="https://book.douban.com/subject/2586390/" target="_blank" rel="noreferrer"><em>Transaction Processing: Concepts and Techniques</em></a> 值得一读，不过我们不建议把这本书当作首要资源。</p><p>如果没有编写足够数量的代码，很难巩固数据库理论。CS 186 课程的学生给 Spark 添加特性，倒是不错的项目，不过我们仅仅建议从零实现一个简单的关系型数据库管理系统。自然，它将不会有太多的特性，但是即便只实现典型的关系型数据库管理系统每个方面最基础的功能，也是相当有启发的。</p><p>最后，数据模型往往是数据库中一个被忽视的、教学不充分的方面。关于这个主题，我们推荐的书籍是 <a href="https://book.douban.com/subject/17915870/" target="_blank" rel="noreferrer"><em>Data and Reality: A Timeless Perspective on Perceiving and Managing Information in Our Imprecise World</em></a>。</p><p><a href="https://book.douban.com/subject/2256069/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66760126-08d27b00-eed4-11e9-82c6-46c571036aa1.jpg" alt="Readings in Database Systems"></a> <a href="https://book.douban.com/subject/1155934/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66760358-85655980-eed4-11e9-9130-66d2ecea5700.jpg" alt="数据库管理系统：原理与设计"></a></p><h3 id="编程语言与编译器" tabindex="-1">编程语言与编译器 <a class="header-anchor" href="#编程语言与编译器" aria-label="Permalink to “编程语言与编译器”">​</a></h3><p>多数程序员学习编程语言的知识，而多数计算机科学家学习编程语言 <strong>相关</strong> 的知识。这使得计算机科学家比起程序员拥有显著的优势，即便在编程领域！因为他们的知识可以推而广之：相较只学习过特定编程语言的人，他们可以更深入更快速地理解新的编程语言。</p><p>我们推荐的入门书是 Bob Nystrom 所著的优秀的 <a href="https://craftinginterpreters.com/contents.html" target="_blank" rel="noreferrer"><em>Crafting Interpreters</em></a>，可在网上免费获取。这本书条理清晰，富有趣味性，非常适合那些想要更好地理解语言和语言工具的人。我们建议你花时间读完整本书，并尝试任何一个感兴趣的「挑战」。</p><p>另一本更为传统的推荐书籍是 <a href="https://book.douban.com/subject/3296317/" target="_blank" rel="noreferrer">《编译原理》</a>，通常称为「龙书」。不幸的是，这本书不是为自学者而设计的，而是供教师从中挑选一些主题用于 1-2 学期的教学。</p><p>如果你选择使用龙书进行自学，你需要从中甄选主题，而且最好是在导师的帮助下。我们建议依据某个视频课程来设定学习的结构，然后按需从龙书中获取深入的内容。我们推荐的在线课程是 <a href="https://www.edx.org/course/compilers" target="_blank" rel="noreferrer">Alex Aiken 在 MOOC 平台 edX 所开设的</a>。</p><p><a href="https://book.douban.com/subject/3296317/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20233656/66760486-ca898b80-eed4-11e9-80ba-df298ac8d5da.jpg" alt="编译原理"></a></p><blockquote><p>不要做一个只写样板代码的程序员。相反，给用户和其他程序员创造工具。从纺织工业和钢铁工业中学习历史教训：你想制造机器和工具，还是操作这些机器？</p><p>— Ras Bodik 在他的编译器课程伊始</p></blockquote><h3 id="分布式系统" tabindex="-1">分布式系统 <a class="header-anchor" href="#分布式系统" aria-label="Permalink to “分布式系统”">​</a></h3><p>随着计算机在数量上的增加，计算机同样开始 <strong>分散</strong>。尽管商业公司过去愿意购买越来越大的大型机，现在的典型情况是，甚至很小的应用程序都同时在多台机器上运行。思考这样做的利弊权衡，即是分布式系统的研究所在，也是越来越重要的一项技能。</p><p>我们推荐的自学参考书是 Martin Kleppmann 的 <a href="https://book.douban.com/subject/30329536/" target="_blank" rel="noreferrer">《数据密集型应用系统设计》</a>。与传统的教科书相比，它是一本为实践者设计的具有很高的可读性的书，并且保持了深度和严谨性。</p><p>对于那些偏爱传统教材，或者希望可以从网上免费获取的人，我们推荐的教材是 Maarten van Steen 和 Andrew Tanenbaum 所著的 《分布式系统原理与范型》（<a href="https://book.douban.com/subject/3108801/" target="_blank" rel="noreferrer">中文第二版</a>，<a href="https://book.douban.com/subject/26979326/" target="_blank" rel="noreferrer">英文第三版</a>）。</p><p>对于喜欢视频课程的人，<a href="https://www.youtube.com/watch?v=cQP8WApzIQQ&amp;list=PLrw6a1wE39_tb2fErI4-WkMbsvGQk9_UB" target="_blank" rel="noreferrer">MIT 的 6.824</a> 是一门很好的在线视频课程，由 Robert Morris 教授的研究生课程，在 <a href="https://pdos.csail.mit.edu/6.824/schedule.html" target="_blank" rel="noreferrer">这里</a> 可以看到课程安排。</p><p>不管选择怎样的教材或者其他辅助资料，学习分布式系统必然要求阅读论文。<a href="http://dsrg.pdos.csail.mit.edu/papers/" target="_blank" rel="noreferrer">这里</a> 有一个不错的论文清单，而且我们强烈建议你出席你当地的 <a href="http://paperswelove.org/" target="_blank" rel="noreferrer">Papers We Love</a>（仅限美国）。</p><p><a href="https://book.douban.com/subject/30329536/" target="_blank" rel="noreferrer"><img src="https://user-images.githubusercontent.com/20510068/82111034-94ff9600-9774-11ea-9d49-90b00f746659.png" alt="数据密集型应用系统设计"></a></p>',92)])])}const f=r(n,[["render",s]]);export{d as __pageData,f as default};
